const input = $('Разбираем входные данные').item.json
let pendingMeta = {}
try { pendingMeta = JSON.parse(String(input.pendingOptionsJson || '{}')) } catch {}

const requestId = String(pendingMeta.requestId || '').trim()
const deliveredAt = String(pendingMeta.deliveredAt || '').trim()
const interactionType = Array.isArray(pendingMeta.questions) ? 'question' : String(pendingMeta.type || 'permission').trim()
const answers = Array.isArray(pendingMeta.answers) ? pendingMeta.answers : []
const rejectRequested = pendingMeta.rejectRequested === true
const permissionReply = String(pendingMeta.reply || '').trim()
const permissionMessage = String(pendingMeta.message || '').trim()
const hasAnswerPayload = interactionType === 'question' ? Boolean(requestId) && (rejectRequested || answers.length > 0) : Boolean(requestId) && Boolean(permissionReply)
const shouldSendQuestion = Boolean(requestId) && !hasAnswerPayload && !deliveredAt && String(input.pendingQuestion || '').trim()

return {
  json: {
    hasAnswerPayload,
    shouldSendQuestion,
    interactionType,
    requestId,
    requestAction: rejectRequested ? 'reject' : 'reply',
    answers,
    permissionReply,
    permissionMessage,
  },
}

const input = $('Разбираем входные данные').item.json
const rawItems = $('Получаем запросы прав').all().map((item) => item.json)
const requests = rawItems.flatMap((item) => Array.isArray(item) ? item : [item]).filter((item) => item && !item.error)
const request = requests.find((item) => String(item.sessionID || '').trim() === input.sessionId)

if (!request) return { json: { hasInteraction: false } }

const patterns = Array.isArray(request.patterns) ? request.patterns : []
const alwaysPatterns = Array.isArray(request.always) ? request.always : []
const metadata = request.metadata && typeof request.metadata === 'object' ? request.metadata : {}
const patternLines = patterns.length > 0 ? patterns.map((pattern) => `- ${String(pattern).trim()}`).join('\n') : '- (паттерн не указан)'
const alwaysLines = alwaysPatterns.length > 0 ? alwaysPatterns.map((pattern) => `- ${String(pattern).trim()}`).join('\n') : '- (нет рекомендуемых паттернов)'
const metadataText = Object.keys(metadata).length > 0 ? JSON.stringify(metadata, null, 2) : ''

const questionText = [
  `OpenCode запрашивает разрешение по задаче ${input.taskKey}.`,
  String(request.title || 'Требуется подтверждение действия.').trim(), '',
  `Тип permission: ${String(request.permission || 'unknown').trim()}`,
  'Запрошенные паттерны:', patternLines, '',
  'Если выбрать always, будут разрешены паттерны:', alwaysLines,
  metadataText ? `\nДополнительные данные:\n${metadataText}` : '', '',
  'Ответьте одним из вариантов:', '1. once - разрешить один раз',
  '2. always - разрешить всегда для предложенных паттернов', '3. reject - отклонить',
].filter(Boolean).join('\n').trim()

return {
  json: {
    hasInteraction: true,
    interactionType: 'permission',
    pendingQuestionText: questionText,
    pendingOptionsJson: JSON.stringify({ type: 'permission', requestId: String(request.id || '').trim(), reply: '', message: '' }),
  },
}

const input = $('Разбираем входные данные').item.json
const rawItems = $('Получаем ожидающие вопросы').all().map((item) => item.json)
const requests = rawItems.flatMap((item) => Array.isArray(item) ? item : [item]).filter((item) => item && !item.error)
const request = requests.find((item) => String(item.sessionID || '').trim() === input.sessionId)

if (!request) return { json: { hasInteraction: false } }

const questions = Array.isArray(request.questions) ? request.questions : []
const blocks = questions.map((question, index) => {
  const lines = []
  lines.push(`${index + 1}. ${String(question.header || '').trim()}`)
  const body = String(question.question || '').trim()
  if (body) lines.push(body)
  const options = Array.isArray(question.options) ? question.options : []
  if (options.length > 0) {
    lines.push('')
    options.forEach((option, i) => { lines.push(`${i + 1}. ${String(option.label || '').trim()}`) })
  }
  lines.push('')
  lines.push(question.multiple ? 'Можно выбрать несколько вариантов.' : 'Выберите один вариант.')
  return lines.join('\n').trim()
})

const questionText = [`OpenCode ждёт уточнение по задаче ${input.taskKey}.`, '', blocks.join('\n\n'), '', 'Для отклонения отправьте /reject или task_key: /reject.'].join('\n').trim()

return {
  json: {
    hasInteraction: true,
    interactionType: 'question',
    pendingQuestionText: questionText,
    pendingOptionsJson: JSON.stringify({ requestId: String(request.id || '').trim(), questions: questions.map((question) => ({ question: String(question.question || '').trim(), header: String(question.header || '').trim(), multiple: Boolean(question.multiple), custom: question.custom !== false, options: (Array.isArray(question.options) ? question.options : []).map((option) => ({ label: String(option.label || '').trim(), description: String(option.description || '').trim() })), })), answers: null, rejectRequested: false }),
  },
}

const launched = $input.item.json
error = $input.item.json

return {
  json: {
    hasAnswerPayload: launched.hasAnswerPayload || false,
    hasInteraction: launched.hasInteraction || false,
  },
}
